insert into public.trip_days (id, date, weekday, city, hotel_id, title, pace, summary, morning, afternoon, evening, optional_plan, transport_note, food_note, reminder, map_url, spots, sort_order, created_at, updated_at) values
  ('day-2026-09-24', '2026-09-24', '周四', '罗马', 'hotel-rome', '抵达罗马，直接休息', 'easy', '23:00 落地罗马，入境取行李后直接前往酒店，预计凌晨入住。', '国内 / 途中。', '途中。', '约 23:00 抵达罗马，前往酒店休息。', '', '机场到市区可用 Leonardo Express 或打车；深夜建议直接打车到酒店。', '落地较晚，随身备少量零食与水。', '提前和住宿确认深夜入住方式，注意可能的夜间入住费。', 'https://www.google.com/maps/search/?api=1&query=Domus+dei+Borgia+Roma', '[]'::jsonb, 1, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z'),
  ('day-2026-09-25', '2026-09-25', '周五', '罗马', 'hotel-rome', '罗马轻松恢复日', 'easy', '前一晚入住较晚，这一天不安排强预约景点，以城市步行和拍照为主。', '睡到自然醒，酒店附近简单吃早饭。', '', '逛完早点回酒店休息。', '', '全程以步行为主，景点集中在老城。', '纳沃纳广场附近咖啡与冰淇淋。', '不要把斗兽场放在这一天。', 'https://www.google.com/maps/search/?api=1&query=Pantheon+Roma', '[{"id":"piazza-venezia","slot":"afternoon","name":"威尼斯广场","images":["/images/piazza-venezia.jpg"]},{"id":"pantheon","slot":"afternoon","name":"万神殿","images":["/images/pantheon.jpg"]},{"id":"piazza-navona","slot":"afternoon","name":"纳沃纳广场","images":["/images/piazza-navona.jpg"]},{"id":"trevi","slot":"evening","name":"特莱维喷泉","images":["/images/trevi.jpg"]},{"id":"spanish-steps","slot":"evening","name":"西班牙广场","images":["/images/spanish-steps.jpg"]}]'::jsonb, 2, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z'),
  ('day-2026-09-26', '2026-09-26', '周六', '罗马', 'hotel-rome', '梵蒂冈', 'medium', '梵蒂冈博物馆 09:30 入场，重点看博物馆、西斯廷礼拜堂，圣彼得大教堂视排队情况决定。', '09:30 入场，建议提前到达。', '', '普拉蒂区（Prati）或返回酒店附近吃饭。', '', '地铁 A 线到 Ottaviano 站步行前往；建议提前到达。', '普拉蒂区餐厅较多，适合午/晚餐。', '已购 09:30 入场票 1 张；另一张需买相近时段（如 10:00）。公开页不展示票码。', 'https://www.google.com/maps/search/?api=1&query=Musei+Vaticani', '[{"id":"vatican-museums","slot":"morning","name":"梵蒂冈博物馆","images":["/images/vatican-museums.jpg"]},{"id":"sistine-chapel","slot":"morning","name":"西斯廷礼拜堂","images":["/images/sistine-chapel.jpg"]},{"id":"piazza-san-pietro","slot":"afternoon","name":"圣彼得广场","images":["/images/piazza-san-pietro.jpg"]},{"id":"st-peters","slot":"afternoon","name":"圣彼得大教堂","images":["/images/st-peters.jpg"]},{"id":"castel-santangelo","slot":"afternoon","name":"圣天使堡","images":["/images/castel-santangelo.jpg"]}]'::jsonb, 3, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z'),
  ('day-2026-09-27', '2026-09-27', '周日', '罗马', 'hotel-rome', '斗兽场轻量游', 'medium', '以拍照和轻量参观为主，不做古罗马深度游。', '', '', '蒙蒂区（Monti）晚餐。', '', '地铁 B 线 Colosseo 站；酒店在蒙蒂区可步行往返。', '蒙蒂区小馆子适合晚餐。', '斗兽场票待订，建议订上午时段。', 'https://www.google.com/maps/search/?api=1&query=Colosseo', '[{"id":"colosseo","slot":"morning","name":"斗兽场","images":["/images/colosseo.jpg"]},{"id":"arch-constantine","slot":"morning","name":"君士坦丁凯旋门","images":["/images/arch-constantine.jpg"]},{"id":"roman-forum","slot":"afternoon","name":"古罗马广场","note":"选择性走一段","images":["/images/roman-forum.jpg"]},{"id":"palatine","slot":"afternoon","name":"帕拉蒂尼山","note":"视体力决定","images":["/images/palatine.jpg"]}]'::jsonb, 4, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z'),
  ('day-2026-09-28', '2026-09-28', '周一', '罗马 → 佛罗伦萨', 'hotel-florence', '前往佛罗伦萨，老城散步', 'medium', '上午从罗马坐高铁到佛罗伦萨，下午轻松游览老城。', '退房，前往 Roma Termini，乘高铁到 Firenze S.M.N.。', '入住或寄存行李。', '老城晚餐。', '', '罗马 Termini → 佛罗伦萨 S.M.N. 高铁约 1.5 小时；高铁待订。', '老城牛肚包、（视预算）佛罗伦萨牛排。', '高铁待订。', 'https://www.google.com/maps/search/?api=1&query=Firenze+Santa+Maria+Novella', '[{"id":"florence-duomo","slot":"afternoon","name":"圣母百花大教堂","images":["/images/florence-duomo.jpg"]},{"id":"piazza-signoria","slot":"afternoon","name":"领主广场","images":["/images/piazza-signoria.jpg"]},{"id":"ponte-vecchio","slot":"afternoon","name":"老桥","images":["/images/ponte-vecchio.jpg"]},{"id":"piazzale-michelangelo","slot":"evening","name":"米开朗琪罗广场","note":"看日落","images":["/images/piazzale-michelangelo.jpg"]}]'::jsonb, 5, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z'),
  ('day-2026-09-29', '2026-09-29', '周二', '佛罗伦萨', 'hotel-florence', '佛罗伦萨轻松游', 'easy', '不做美术馆深度游，以老城、拍照、散步和日落为主。', '', '', '老城晚餐，或再次去米开朗琪罗广场看夜景。', '如果临时想看美术馆，乌菲兹和学院美术馆二选一，不建议都去。', '全程步行；老城不大。', '中央市场（Mercato Centrale）二楼美食广场。', '', 'https://www.google.com/maps/search/?api=1&query=Piazzale+Michelangelo', '[{"id":"florence-baptistery","slot":"morning","name":"洗礼堂","images":["/images/florence-baptistery.jpg"]},{"id":"piazza-repubblica","slot":"morning","name":"共和广场","images":["/images/piazza-repubblica.jpg"]},{"id":"arno-river","slot":"afternoon","name":"阿诺河沿岸","images":["/images/arno-river.jpg"]},{"id":"pitti-palace","slot":"afternoon","name":"皮蒂宫","images":["/images/pitti-palace.jpg"]}]'::jsonb, 6, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z'),
  ('day-2026-09-30', '2026-09-30', '周三', '佛罗伦萨 → 米兰', 'hotel-milan', '前往米兰，大教堂区域', 'medium', '上午高铁去米兰，下午游览米兰大教堂和市中心。', '退房，乘高铁前往 Milano Centrale。', '入住或寄存行李。', '布雷拉街区或运河区晚餐。', '', '佛罗伦萨 S.M.N. → 米兰中央站高铁约 2 小时；高铁待订。', '布雷拉（Brera）一带餐厅与酒吧。', '高铁待订；米兰公寓需确认自助入住方式。', 'https://www.google.com/maps/search/?api=1&query=Duomo+di+Milano', '[{"id":"milano-duomo","slot":"afternoon","name":"米兰大教堂","images":["/images/milano-duomo.jpg"]},{"id":"galleria-milano","slot":"afternoon","name":"埃马努埃莱二世长廊","images":["/images/galleria-milano.jpg"]}]'::jsonb, 7, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z'),
  ('day-2026-10-01', '2026-10-01', '周四', '米兰', 'hotel-milan', '米兰轻松游', 'easy', '以城市街区、建筑和公园为主，不执着博物馆。', '', '布雷拉街区散步。', '纳维利运河区（Navigli）晚餐。', '如买到《最后的晚餐》合适时段，可替换上午部分安排。', '地铁便利；城堡与长廊之间可步行。', '纳维利运河区适合 Aperitivo（餐前酒）。', '《最后的晚餐》需很早预约，如未订则跳过。', 'https://www.google.com/maps/search/?api=1&query=Castello+Sforzesco', '[{"id":"castello-sforzesco","slot":"morning","name":"斯福尔扎城堡","images":["/images/castello-sforzesco.jpg"]},{"id":"parco-sempione","slot":"morning","name":"森皮奥内公园","images":["/images/parco-sempione.jpg"]},{"id":"arco-della-pace","slot":"morning","name":"和平门","images":["/images/arco-della-pace.jpg"]},{"id":"brera","slot":"afternoon","name":"布雷拉美术馆","note":"可选","images":["/images/brera.jpg"]}]'::jsonb, 8, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z'),
  ('day-2026-10-02', '2026-10-02', '周五', '米兰 → 威尼斯', 'hotel-venice', '早到威尼斯', 'medium', '早班高铁前往威尼斯，尽量上午到达，下午和晚上游览本岛。', '退房，乘早班高铁前往 Venezia Santa Lucia。', '入住或寄存行李。', '多尔索杜罗区散步。', '', '米兰中央站 → 威尼斯 S. Lucia 高铁约 2.5 小时；建议早班车，高铁待订。', '本岛餐厅偏贵，可找小巷里的 bacaro 吃 cicchetti。', '不建议安排彩色岛或玻璃岛。', 'https://www.google.com/maps/search/?api=1&query=Venezia+Santa+Lucia', '[{"id":"rialto","slot":"afternoon","name":"里亚托桥","images":["/images/rialto.jpg"]},{"id":"piazza-san-marco","slot":"afternoon","name":"圣马可广场","images":["/images/piazza-san-marco.jpg"]},{"id":"basilica-san-marco","slot":"afternoon","name":"圣马可大教堂","images":["/images/basilica-san-marco.jpg"]},{"id":"grand-canal","slot":"evening","name":"大运河夜景","images":["/images/grand-canal.jpg"]},{"id":"accademia-bridge","slot":"evening","name":"学院桥","images":["/images/accademia-bridge.jpg"]}]'::jsonb, 9, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z'),
  ('day-2026-10-03', '2026-10-03', '周六', '威尼斯 → 机场', NULL, '威尼斯清晨散步，前往机场', 'easy', '上午轻松散步，下午按同行人 17:45 航班时间前往机场。', '喝咖啡，补拍照片。', '回酒店取行李，前往机场。', '本人 21:30 从威尼斯起飞回国。', '', '先确认机场是 VCE（马可波罗）还是 TSF（特雷维索）；VCE 可乘水上巴士 / 机场巴士，预留充足时间。', '出发前在火车站附近简单解决。', '若为 VCE，建议较早出发，避免拖行李赶时间；配合同行人 17:45 航班。', 'https://www.google.com/maps/search/?api=1&query=Venezia+Marco+Polo+Airport', '[{"id":"piazza-san-marco-morning","slot":"morning","name":"圣马可广场","note":"清晨人少，适合拍照","images":["/images/piazza-san-marco.jpg"]}]'::jsonb, 10, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z')
insert into public.hotels (id, city, name, check_in, check_out, nights, area_note, transport_note, public_note, sort_order, created_at, updated_at) values
  ('hotel-rome', '罗马', 'Domus dei Borgia', '2026-09-24', '2026-09-28', 4, '罗马蒙蒂区，靠近斗兽场、古罗马区域和 Cavour 地铁站，适合罗马前几天游览。', '地铁 B 线 Cavour 站附近；机场深夜抵达建议打车直达。', '9/24 约 23:00 落地，预计凌晨入住，需提前确认深夜入住方式与可能的夜间入住费。', 1, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z'),
  ('hotel-florence', '佛罗伦萨', 'Domus Plaza', '2026-09-28', '2026-09-30', 2, '佛罗伦萨老城核心，步行可达大教堂、领主广场、老桥。', '从 Firenze S.M.N. 火车站步行可达。', '', 2, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z'),
  ('hotel-milan', '米兰', 'APARTMENT MIKI - MAURO MACCHI 91', '2026-09-30', '2026-10-02', 2, '靠近 Milano Centrale 一带，适合高铁进出米兰。', '距米兰中央站步行约 10 分钟。', '公寓型住宿，需确认自助入住、行李寄存、电梯与城市税。', 3, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z'),
  ('hotel-venice', '威尼斯', 'Abbazia De Luxe', '2026-10-02', '2026-10-03', 1, '靠近 Venezia Santa Lucia 火车站，适合只住一晚、次日前往机场。', '从威尼斯 S. Lucia 火车站步行可达，免拖行李过太多桥。', '', 4, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z')
