  ('booking-arrival-flight', 'flight', '抵达罗马航班', '2026-09-24', '23:00', '罗马', 'booked', true, '晚上 23:00 落地罗马，当晚直接前往酒店休息。', 1, '2026-07-01T00:00:00.000Z', '2026-07-01T00:00:00.000Z'),
